import{_ as e,o as i,c as a,ag as o}from"./chunks/framework.YaIgwL5o.js";const p=JSON.parse('{"title":"Text & Formatting","description":"","frontmatter":{},"headers":[],"relativePath":"features/text-formatting.md","filePath":"features/text-formatting.md"}'),l={name:"features/text-formatting.md"};function s(n,t,r,d,h,c){return i(),a("div",null,[...t[0]||(t[0]=[o(`<h1 id="text-formatting" tabindex="-1">Text &amp; Formatting <a class="header-anchor" href="#text-formatting" aria-label="Permalink to &quot;Text &amp; Formatting&quot;">​</a></h1><p>Slides Editor uses <a href="https://tiptap.dev/" target="_blank" rel="noreferrer">TipTap</a> as its rich text engine, giving you full control over typography directly on the slide canvas.</p><h2 id="activating-the-text-editor" tabindex="-1">Activating the text editor <a class="header-anchor" href="#activating-the-text-editor" aria-label="Permalink to &quot;Activating the text editor&quot;">​</a></h2><p>Double-click any text element to enter editing mode. A <strong>formatting toolbar</strong> appears above or below the element with all available options.</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>You can also single-click a text element to select it, then press <code>Enter</code> to start editing.</p></div><h2 id="headings" tabindex="-1">Headings <a class="header-anchor" href="#headings" aria-label="Permalink to &quot;Headings&quot;">​</a></h2><p>Use the heading dropdown in the toolbar to set the level:</p><ul><li><strong>Heading 1</strong> — large title text</li><li><strong>Heading 2</strong> — subtitle / section heading</li><li><strong>Heading 3</strong> — sub-section</li><li><strong>Paragraph</strong> — normal body text</li></ul><h2 id="inline-styles" tabindex="-1">Inline styles <a class="header-anchor" href="#inline-styles" aria-label="Permalink to &quot;Inline styles&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Style</th><th>Toolbar button</th><th>Shortcut</th></tr></thead><tbody><tr><td>Bold</td><td><strong>B</strong></td><td><code>Ctrl+B</code></td></tr><tr><td>Italic</td><td><em>I</em></td><td><code>Ctrl+I</code></td></tr><tr><td>Underline</td><td>U̲</td><td><code>Ctrl+U</code></td></tr><tr><td>Strikethrough</td><td><s>S</s></td><td><code>Ctrl+Shift+X</code></td></tr><tr><td>Highlight</td><td>H</td><td><code>Ctrl+Shift+H</code></td></tr><tr><td>Inline code</td><td><code>{ }</code></td><td><code>Ctrl+\`</code></td></tr><tr><td>Inline math</td><td>∑</td><td>via toolbar</td></tr></tbody></table><h2 id="text-color-highlight" tabindex="-1">Text color &amp; highlight <a class="header-anchor" href="#text-color-highlight" aria-label="Permalink to &quot;Text color &amp; highlight&quot;">​</a></h2><p>Click the <strong>A</strong> (text color) or <strong>highlight</strong> icon in the toolbar to open a color picker. You can choose:</p><ul><li>A preset palette color</li><li>A custom hex or RGB value</li><li>Transparent (to remove highlight)</li></ul><h2 id="font-family-size" tabindex="-1">Font family &amp; size <a class="header-anchor" href="#font-family-size" aria-label="Permalink to &quot;Font family &amp; size&quot;">​</a></h2><ul><li><strong>Font family</strong> — choose from a curated set of web-safe and Google Fonts (serif, sans-serif, monospace, display)</li><li><strong>Font size</strong> — type a value in the size box or use the up/down arrows; size is in points relative to the slide</li></ul><h2 id="text-alignment" tabindex="-1">Text alignment <a class="header-anchor" href="#text-alignment" aria-label="Permalink to &quot;Text alignment&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Alignment</th><th>Shortcut</th></tr></thead><tbody><tr><td>Left</td><td><code>Ctrl+Shift+L</code></td></tr><tr><td>Center</td><td><code>Ctrl+Shift+E</code></td></tr><tr><td>Right</td><td><code>Ctrl+Shift+R</code></td></tr><tr><td>Justify</td><td><code>Ctrl+Shift+J</code></td></tr></tbody></table><h2 id="lists" tabindex="-1">Lists <a class="header-anchor" href="#lists" aria-label="Permalink to &quot;Lists&quot;">​</a></h2><ul><li><strong>Bullet list</strong> — toolbar bullet icon or <code>Ctrl+Shift+8</code></li><li><strong>Ordered list</strong> — toolbar number icon or <code>Ctrl+Shift+7</code></li><li>Nest items by pressing <code>Tab</code>; un-nest with <code>Shift+Tab</code></li></ul><h2 id="tables" tabindex="-1">Tables <a class="header-anchor" href="#tables" aria-label="Permalink to &quot;Tables&quot;">​</a></h2><p>Insert a table from the toolbar&#39;s <strong>Table</strong> button. After inserting:</p><ul><li>Click a cell to edit its content</li><li>Right-click for row/column add/delete options</li><li>Drag column borders to resize</li></ul><h2 id="code-blocks" tabindex="-1">Code blocks <a class="header-anchor" href="#code-blocks" aria-label="Permalink to &quot;Code blocks&quot;">​</a></h2><p>Insert a fenced code block from the toolbar. Select the language from the dropdown for syntax highlighting (powered by highlight.js).</p><div class="language-python vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Example Python code block on a slide</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">def</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> greet</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(name: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">str</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) -&gt; </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">str</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    return</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> f</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Hello, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">{</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">name</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">}</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">!&quot;</span></span></code></pre></div><h2 id="links" tabindex="-1">Links <a class="header-anchor" href="#links" aria-label="Permalink to &quot;Links&quot;">​</a></h2><p>Select text and click the <strong>link</strong> icon in the toolbar (or press <code>Ctrl+K</code>) to add a hyperlink. Links open in a new tab when clicked in presentation mode.</p><h2 id="inline-math" tabindex="-1">Inline math <a class="header-anchor" href="#inline-math" aria-label="Permalink to &quot;Inline math&quot;">​</a></h2><p>Type a LaTeX expression surrounded by <code>$</code> signs inside any text element, or use the toolbar&#39;s <strong>math</strong> (∑) button:</p><ul><li><code>$E = mc^2$</code> renders inline as $E = mc^2$</li><li>Inline math is rendered via KaTeX</li></ul><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>For full display-math equations or TikZ diagrams, use a dedicated <strong>LaTeX block</strong> element instead. See <a href="/revealjs_gui/features/latex.html">LaTeX &amp; Math</a> for details.</p></div>`,31)])])}const u=e(l,[["render",s]]);export{p as __pageData,u as default};
